# Category: mfa_bypass

from flask import Flask, request, session, redirect, url_for, render_template_string, jsonify
from werkzeug.security import generate_password_hash, check_password_hash
import secrets
import time

app = Flask(__name__)
app.secret_key = secrets.token_hex(32)

users = {
    "alice": {
        "password_hash": generate_password_hash("password123"),
        "mfa_enabled": True,
        "otp_secret": "123456",
        "roles": ["web"]
    },
    "bob": {
        "password_hash": generate_password_hash("bobpass"),
        "mfa_enabled": False,
        "otp_secret": None,
        "roles": ["web", "api"]
    },
    "service_account": {
        "password_hash": generate_password_hash("servicepass"),
        "mfa_enabled": True,
        "otp_secret": "654321",
        "roles": ["api"]
    }
}

api_tokens = {}
pending_mfa = {}

LOGIN_TEMPLATE = """
<!doctype html>
<title>Login</title>
<h2>Login</h2>
{% if error %}<p style="color:red">{{ error }}</p>{% endif %}
<form method="post">
  <label>Username</label><br>
  <input type="text" name="username" required><br><br>
  <label>Password</label><br>
  <input type="password" name="password" required><br><br>
  <button type="submit">Login</button>
</form>
"""

OTP_TEMPLATE = """
<!doctype html>
<title>MFA Verification</title>
<h2>Enter OTP</h2>
{% if error %}<p style="color:red">{{ error }}</p>{% endif %}
<form method="post">
  <label>One-Time Password</label><br>
  <input type="text" name="otp" required><br><br>
  <button type="submit">Verify</button>
</form>
"""

HOME_TEMPLATE = """
<!doctype html>
<title>Home</title>
<h2>Welcome {{ username }}</h2>
<p>Authenticated successfully.</p>
<p>MFA verified: {{ mfa_verified }}</p>
<a href="{{ url_for('logout') }}">Logout</a>
"""

def get_user(username):
    return users.get(username)

def authenticate_user(username, password):
    user = get_user(username)
    if not user:
        return False
    return check_password_hash(user["password_hash"], password)

def verify_otp(username, otp):
    user = get_user(username)
    if not user or not user.get("mfa_enabled"):
        return False
    return str(user.get("otp_secret")) == str(otp)

def create_api_token(username):
    token = secrets.token_urlsafe(32)
    api_tokens[token] = {
        "username": username,
        "issued_at": int(time.time())
    }
    return token

def login_user(username, mfa_verified=False):
    session.clear()
    session["authenticated"] = True
    session["username"] = username
    session["mfa_verified"] = mfa_verified

def logout_user():
    session.clear()

def is_logged_in():
    return session.get("authenticated") is True and "username" in session

@app.route("/")
def home():
    if not is_logged_in():
        return redirect(url_for("login"))
    return render_template_string(
        HOME_TEMPLATE,
        username=session["username"],
        mfa_verified=session.get("mfa_verified", False)
    )

@app.route("/login", methods=["GET", "POST"])
def login():
    if request.method == "GET":
        return render_template_string(LOGIN_TEMPLATE, error=None)

    username = request.form.get("username", "").strip()
    password = request.form.get("password", "")

    if not authenticate_user(username, password):
        return render_template_string(LOGIN_TEMPLATE, error="Invalid username or password"), 401

    user = get_user(username)

    if user.get("mfa_enabled"):
        challenge_id = secrets.token_urlsafe(16)
        pending_mfa[challenge_id] = {
            "username": username,
            "created_at": int(time.time())
        }
        session.clear()
        session["pending_mfa_challenge"] = challenge_id
        return redirect(url_for("mfa_verify"))

    login_user(username, mfa_verified=False)
    return redirect(url_for("home"))

@app.route("/mfa", methods=["GET", "POST"])
def mfa_verify():
    challenge_id = session.get("pending_mfa_challenge")
    if not challenge_id or challenge_id not in pending_mfa:
        return redirect(url_for("login"))

    challenge = pending_mfa[challenge_id]
    username = challenge["username"]

    if request.method == "GET":
        return render_template_string(OTP_TEMPLATE, error=None)

    otp = request.form.get("otp", "").strip()
    if not verify_otp(username, otp):
        return render_template_string(OTP_TEMPLATE, error="Invalid OTP"), 401

    pending_mfa.pop(challenge_id, None)
    login_user(username, mfa_verified=True)
    return redirect(url_for("home"))

@app.route("/logout")
def logout():
    challenge_id = session.get("pending_mfa_challenge")
    if challenge_id:
        pending_mfa.pop(challenge_id, None)
    logout_user()
    return redirect(url_for("login"))

@app.route("/api/direct-login", methods=["POST"])
def api_direct_login():
    data = request.get_json(silent=True) or {}
    username = (data.get("username") or "").strip()
    password = data.get("password") or ""

    if not username or not password:
        return jsonify({"error": "username and password are required"}), 400

    if not authenticate_user(username, password):
        return jsonify({"error": "invalid credentials"}), 401

    token = create_api_token(username)
    return jsonify({
        "message": "authenticated",
        "username": username,
        "mfa_skipped": True,
        "access_token": token,
        "token_type": "Bearer"
    })

@app.route("/api/protected", methods=["GET"])
def api_protected():
    auth_header = request.headers.get("Authorization", "")
    if not auth_header.startswith("Bearer "):
        return jsonify({"error": "missing or invalid authorization header"}), 401

    token = auth_header.split(" ", 1)[1].strip()
    token_data = api_tokens.get(token)
    if not token_data:
        return jsonify({"error": "invalid token"}), 401

    return jsonify({
        "message": "protected resource accessed",
        "username": token_data["username"],
        "issued_at": token_data["issued_at"]
    })

if __name__ == "__main__":
    app.run(debug=True)